// 读取规则.docx 文档内容
try {
    var ruleDoc = null;
    var docs = Application.Documents;
    for (var i = 1; i <= docs.Count; i++) {
        if (docs.Item(i).Name === "规则.docx") {
            ruleDoc = docs.Item(i);
            break;
        }
    }

    if (!ruleDoc) {
        return { success: false, error: "未找到规则.docx 文档" };
    }

    var content = "";
    var paras = ruleDoc.Paragraphs;
    for (var j = 0; j < paras.Count; j++) {
        content += paras.Item(j).Text + "\n";
    }

    return { success: true, content: content };
} catch (e) {
    return { success: false, error: e.message };
}

